import { createActivationKey, getDeviceHash, hashActivationKey, randomToken } from '@aegis/licensing';
export function buildLicensePayload(input) { return { type: 'AEGIS_LICENSE', licenseId: crypto.randomUUID(), requestId: input.request.requestId, deviceId: input.request.deviceId, deviceHash: getDeviceHash(input.request.deviceId), telegramUserId: input.telegramUserId, telegramUsername: input.telegramUsername, plan: input.plan, features: input.features, maxDevices: 1, activationLimit: 1, issuedAt: new Date().toISOString(), expiresAt: input.expiresAt, activationNonce: randomToken(), keyId: input.keyId, appVersionMin: input.appVersionMin ?? '1.0.0', appVersionMax: input.appVersionMax ?? null }; }
export function issueActivationKey(payload, privateKeyPem) { const activationKey = createActivationKey(payload, privateKeyPem); return { activationKey, activationKeyHash: hashActivationKey(activationKey) }; }
